pub fn loadBaseFunctions() void
{
	VulkanInclude.vkEnumerateInstanceExtensionProperties = @ptrCast(VulkanInclude.vkGetInstanceProcAddr(null, "vkEnumerateInstanceExtensionProperties"));
	VulkanInclude.vkEnumerateInstanceLayerProperties = @ptrCast(VulkanInclude.vkGetInstanceProcAddr(null, "vkEnumerateInstanceLayerProperties"));
	VulkanInclude.vkEnumerateInstanceVersion = @ptrCast(VulkanInclude.vkGetInstanceProcAddr(null, "vkEnumerateInstanceVersion"));
	VulkanInclude.vkCreateInstance = @ptrCast(VulkanInclude.vkGetInstanceProcAddr(null, "vkCreateInstance"));
}
pub fn loadInstanceFunctions() void
