	VulkanInclude.vkEnumeratePhysicalDevices = @ptrCast(VulkanInclude.vkGetInstanceProcAddr(VulkanGlobalState._instance, "vkEnumeratePhysicalDevices"));
	VulkanInclude.vkGetPhysicalDeviceProperties = @ptrCast(VulkanInclude.vkGetInstanceProcAddr(VulkanGlobalState._instance, "vkGetPhysicalDeviceProperties"));
